nflquery = '           '.split(' ')
nflquery.append("SELECT  p2.PlayType,p2.RunLocation,AVG(p2.YardsGained) AS AllTeams_RushAvg,p3.PHI_RushAvg AS PHI_RushAvg,p3.PHI_RushAttempts FROM (SELECT  DISTINCT DefensiveTeam AS DefTeam,posteam FROM plays WHERE posteam = 'PHI') AS p1 JOIN plays p2 ON p2.DefensiveTeam = p1.DefTeam JOIN (SELECT  posteam,PlayType,RunLocation AS PhiRunLocation,AVG(YardsGained) AS PHI_RushAvg,COUNT(*) AS PHI_RushAttempts FROM plays WHERE posteam = 'PHI' AND PlayType = 'Run' AND RunLocation IS NOT NULL GROUP BY RunLocation) AS p3 ON p2.RunLocation = p3.PhiRunLocation WHERE p2.PlayType = 'Run' AND p2.RunLocation IS NOT NULL GROUP BY p2.RunLocation ORDER BY AVG(p2.YardsGained) DESC;")

nflquery.append("SELECT  p2.PassOutcome,p2.PassLength,AVG(p2.YardsGained) AS AllTeams_PassAvg,p3.PHI_PassAvg AS PHI_PassAvg FROM (SELECT  DISTINCT DefensiveTeam AS DefTeam,posteam FROM plays WHERE posteam = 'PHI') AS p1 JOIN plays p2 ON p2.DefensiveTeam = p1.DefTeam JOIN (SELECT  posteam,PassOutcome,PassLength AS PhiPassLength,AVG(YardsGained) AS PHI_PassAvg,COUNT(*) AS PHI_CompletePasses FROM plays WHERE posteam = 'PHI' AND PassOutcome = 'Complete' AND PassLength IS NOT NULL GROUP BY PassLength) AS p3 ON p2.PassLength = p3.PhiPassLength WHERE p2.PassOutcome = 'Complete' AND p2.PassLength IS NOT NULL GROUP BY p2.PassLength ORDER BY AVG(p2.YardsGained) DESC;")

nflquery.append("SELECT COUNT(*) FROM plays WHERE plays.posteam = 'PHI' AND plays.PlayType = 'Pass' INTO @eaglespassplays; SELECT  COUNT(*) FROM (SELECT DISTINCT DefensiveTeam AS DefTeam, posteam FROM plays WHERE posteam = 'PHI') AS p1 JOIN plays p2 ON p2.DefensiveTeam = p1.DefTeam WHERE p2.PlayType = 'Pass'INTO @totalpassplays;SELECT p2.PassOutcome,p2.PassLength,AVG(p2.YardsGained) AS AllTeams_PassAvg,p3.PHI_PassAvg AS PHI_PassAvg,COUNT(*) / @totalpassplays * 100 AS AllTeams_CompletionPercentage,p3.PHI_CompletePasses / @eaglespassplays * 100 AS PHI_CompletionPercentage FROM (SELECT DISTINCT DefensiveTeam AS DefTeam, posteam FROM plays WHERE posteam = 'PHI') AS p1 JOIN plays p2 ON p2.DefensiveTeam = p1.DefTeam JOIN (SELECT  posteam,PassOutcome,PassLength AS PhiPassLength,AVG(YardsGained) AS PHI_PassAvg,COUNT(*) AS PHI_CompletePasses FROM plays WHERE posteam = 'PHI' AND PassOutcome = 'Complete' AND PassLength IS NOT NULL GROUP BY PassLength) AS p3 ON p2.PassLength = p3.PhiPassLength WHERE p2.PassOutcome = 'Complete' AND p2.PassLength IS NOT NULL GROUP BY p2.PassLength ORDER BY AVG(p2.YardsGained) DESC;")

def GetQuery():
    return nflquery